  const grid=m.yTicks.map(t=>`<line class="cw-grid" x1="0" y1="${t.y}" x2="100" y2="${t.y}"/>`).join('');
  const today=`<line class="cw-today" x1="${m.todayX}" y1="0" x2="${m.todayX}" y2="100"/>`;
  const tgt=m.targetInView?`<line class="cw-target" x1="0" y1="${m.targetY}" x2="100" y2="${m.targetY}"/>`:'';
