  const svg=`<svg viewBox="0 0 100 100" preserveAspectRatio="none" class="cw-forecast-svg" aria-hidden="true">${grid}${tgt}${today}<polyline class="cw-plan-line" points="${pts(m.plan)}"/>${m.actual.length>=2?`<polyline class="cw-actual-line" points="${pts(m.actual)}"/>`:''}</svg>`;
