function renderTonnageTrend(){const el=$('#tonnageTrend');if(!el||typeof weeklyTonnageTrend!=='function')return;const t=weeklyTonnageTrend(state.workouts,localDate(),8);if(!t){el.hidden=true;el.innerHTML='';return;}el.hidden=false;el.className='tonnage-trend tt-'+t.trend;const arrow=t.trend==='up'?'📈':t.trend==='down'?'📉':'➡️',kg=n=>Math.round(n).toLocaleString('fr-FR'),sign=n=>(n>0?'+':'')+n;const bars=t.weeks.map((w,i)=>{const h=t.max>0?Math.max(4,Math.round(w.tonnage/t.max*100)):4,isLast=i===t.weeks.length-1,d=w.start.split('-'),lbl=`${d[2]}/${d[1]}`;return `<div class="tt-bar${isLast?' tt-last':''}${w.tonnage===0?' tt-empty':''}" style="height:${h}%" title="Sem. ${lbl} · ${kg(w.tonnage)} kg · ${w.sessions} séance${w.sessions>1?'s':''}"></div>`;}).join('');const rec=(typeof bestSessionTonnage==='function')?bestSessionTonnage(state.workouts):null;const recHtml=rec?`<div class="tt-record${rec.isLatest?' tt-record-new':''}">🏆 ${rec.isLatest?'<b>Nouveau record séance !</b>':'Record séance :'} <b>${kg(rec.tonnage)} kg</b> · ${rec.date.split('-').reverse().slice(0,2).join('/')}</div>`:'';const recW=(typeof bestTonnageWeek==='function')?bestTonnageWeek(state.workouts,localDate()):null;const recWHtml=recW?`<div class="tt-record${recW.isCurrent?' tt-record-new':''}">🗓️ ${recW.isCurrent?'<b>Record hebdo battu cette semaine !</b>':'Record hebdo :'} <b>${kg(recW.tonnage)} kg</b> · sem. ${recW.weekStart.split('-').reverse().slice(0,2).join('/')}</div>`:'';el.innerHTML=`<div class="tt-head"><b>${arrow} Tonnage muscu · 8 semaines</b><span>${t.avgPrior>0?`cette sem. ${sign(t.deltaPct)} % vs moyenne`:'première semaine chiffrée'}</span></div><div class="tt-chart">${bars}</div><small>Cette semaine : <b>${kg(t.last)} kg</b> soulevés · pic ${kg(t.max)} kg.</small>${recHtml}${recWHtml}`;}
