$('#wpSchedule')?.addEventListener('click',()=>{if(!lastWeekProgram)return;const n=scheduleWeekProgram(lastWeekProgram,4);$('#wpScheduleStatus').textContent=n?`✓ ${n} séances programmées dès CETTE semaine (jours restants) puis les suivantes — modifiables dans l’agenda.`:'Déjà programmé : aucun doublon ajouté.';});
