$('#exerciseCards').onclick=e=>{const index=e.target.closest('[data-exercise]')?.dataset.exercise;if(index===undefined)return;selectedExercise=exercises[index];const p=exercisePrescription(selectedExercise),progression=p.unit==='reps'?`Quand toutes les séries sont propres et gardent 2–3 répétitions en réserve, ajoute 1 répétition par série ou un peu de charge.`:`Quand le format reste stable et confortable, ajoute 5 secondes ou quelques pas, jamais tout d’un coup.`;const _hist=exerciseHistoryStats(state.workouts,selectedExercise.name),_sugg=progressionSuggestion(state.workouts,selectedExercise.name,{minReps:8,maxReps:12,increment:progressionIncrement(selectedExercise.name)});let histBlock='';if(_hist){const parts=[`<div class="ex-hist-line">🗓️ <b>${_hist.sessions}</b> séance${_hist.sessions>1?'s':''}${_hist.lastDate?` · dernière le ${_hist.lastDate.split('-').reverse().join('/')}`:''}${_hist.totalSets?` · ${_hist.totalSets} série${_hist.totalSets>1?'s':''} au total`:''}</div>`];if(_hist.bestSet&&_hist.bestSet.load>0)parts.push(`<div class="ex-hist-line">🏆 Meilleure série : <b>${_hist.bestSet.load} kg × ${_hist.bestSet.reps}</b> <small>(1RM est. ${_hist.bestSet.e1rm} kg)</small></div>`);else if(_hist.bestReps>0)parts.push(`<div class="ex-hist-line">🏆 Meilleure série : <b>${_hist.bestReps} reps</b></div>`);if(_sugg)parts.push(`<div class="ex-hist-next">${progressionText(_sugg)}</div>`);const _vol=exerciseVolumeSeries(exerciseEntries().map(x=>({name:x.name,date:x.workout.date,volume:x.volume})),selectedExercise.name,8);if(_vol.length>=2&&_vol.some(pt=>pt.volume>0))parts.push(`<div class="ex-hist-spark"><span class="ex-hist-spark-label">Volume · ${_vol.length} dernières séances</span>${barChartSvg(_vol.map(pt=>({total:pt.volume,label:pt.date.split('-').reverse().join('/')})),{color:'var(--accent)',unit:' kg',decimals:0})}</div>`);histBlock=`<div class="ex-hist">${parts.join('')}</div>`;}$('#exerciseDetailTitle').textContent=selectedExercise.name;$('#exerciseDetailPose').innerHTML=exercisePicture(selectedExercise.name,'',true);$('#exerciseDetailCue').textContent=selectedExercise.cue;$('#exerciseDetailNotes').innerHTML=histBlock+`<div><b>Format de départ :</b> ${exerciseFormat(selectedExercise)} · repos ${p.rest}s · environ ${p.minutes} min.</div><div><b>Exécution :</b> ${selectedExercise.explain}</div><div><b>Objectif :</b> ${selectedExercise.goal}</div><div><b>Progression :</b> ${progression}</div><div><b>À éviter :</b> ${selectedExercise.avoid}</div>`;updateFavButton();$('#exerciseDetailDialog').showModal();};
function updateFavButton(){const b=$('#toggleFavExercise');if(!b||!selectedExercise)return;const fav=(state.exerciseFavorites||[]).includes(selectedExercise.name);b.textContent=fav?'★ Retirer des favoris':'☆ Ajouter aux favoris';b.classList.toggle('is-fav',fav);}
