$('#guidedSetLog').onclick=e=>{const adj=e.target.closest('[data-guided-sets]');if(adj&&guidedWorkout&&typeof adjustGuidedSets==='function'){saveGuidedExercise();const current=guidedWorkout.exercises[guidedIndex],r=adjustGuidedSets(current,Number(adj.dataset.guidedSets));if(!r)return;if(r.changed){current.sets=r.sets;if(Array.isArray(current.setLogs))current.setLogs=current.setLogs.slice(0,r.sets);haptic('setDone');renderGuidedWorkout();}else{const msg={min:'Il faut garder au moins une série.',max:'Maximum 8 séries pour cet exercice.',completed:'Cette série est déjà validée — décoche-la d’abord pour la retirer.'}[r.reason];if(msg)flashToast(msg,2600);}return;}
  const button=e.target.closest('[data-complete-guided-set]');if(!button||!guidedWorkout)return;saveGuidedExercise();const current=guidedWorkout.exercises[guidedIndex],set=current.setLogs[Number(button.dataset.completeGuidedSet)];if(!set)return;set.completed=!set.completed;current.completedSets=current.setLogs.filter(x=>x.completed).length;const idx=Number(button.dataset.completeGuidedSet);let pr=null;if(set.completed&&typeof liveSetRecord==='function'){const others=current.setLogs.filter((s,i)=>i!==idx&&s.completed);pr=liveSetRecord(personalRecords(state.workouts),current.name,set,others);}renderGuidedWorkout();if(set.completed){if(pr){const detail=pr.type==='load'?`${String(pr.value).replace('.',',')} kg (avant : ${String(pr.previous).replace('.',',')} kg)`:`${pr.value} reps (avant : ${pr.previous})`;flashToast(`🎉 Record battu · ${current.name} — ${detail} !`,3800);haptic('record');}else{haptic('setDone');}startGuidedRest();}};
