function applyImportedIcs(text,kind){let events=[];try{events=parseIcs(String(text),{kind,baseId:Date.now()});}catch{}if(!events.length)return{total:0,rec:0};const recEvents=events.filter(ev=>ev.recurrence),oneOff=events.filter(ev=>!ev.recurrence);if(oneOff.length)state.agenda=mergePlannedEvents(state.agenda,oneOff).map(normalizeAgendaItem);if(recEvents.length)state.recurring=mergeRecurring(state.recurring,recEvents.map(ev=>({id:ev.id,title:ev.title,time:ev.allDay?'':ev.time,kind,priority:'normal',rule:ev.recurrence,refId:ev.refId})));return{total:events.length,rec:recEvents.length};}
